import 'dart:io'; import 'package:flutter/material.dart'; import 'package:flutter_riverpod/flutter_riverpod.dart'; import 'package:image_picker/image_picker.dart'; import '../../../../core/widgets/app_snackbar.dart'; import '../../domain/entities/report.dart'; import '../providers/report_providers.dart'; import '../widgets/report_form.dart';
class ReportPage extends ConsumerStatefulWidget{final String targetId; final ReportTargetType targetType; const ReportPage({super.key,required this.targetId,required this.targetType}); @override ConsumerState<ReportPage> createState()=>_ReportPageState();}
class _ReportPageState extends ConsumerState<ReportPage>{final desc=TextEditingController(); final picker=ImagePicker(); ReportReason reason=ReportReason.other; final images=<File>[]; @override void dispose(){desc.dispose();super.dispose();} Future<void> add() async{final picked=await picker.pickMultiImage(imageQuality:85); setState(()=>images.addAll(picked.map((e)=>File(e.path))));} Future<void> submit() async{final id=await ref.read(reportControllerProvider.notifier).submitReport(targetId:widget.targetId,targetType:widget.targetType,reason:reason,description:desc.text,evidenceImages:images); if(!mounted)return; final st=ref.read(reportControllerProvider); if(st.errorMessage!=null)return AppSnackbar.error(context,st.errorMessage!); if(id!=null){AppSnackbar.success(context,'Report submitted'); Navigator.pop(context);}} @override Widget build(BuildContext context){final st=ref.watch(reportControllerProvider); return Scaffold(appBar:AppBar(title:const Text('Report')),body:ReportForm(reason:reason,onReasonChanged:(v)=>setState(()=>reason=v),descriptionController:desc,evidenceImages:images,onAddImage:add,onRemoveImage:(i)=>setState(()=>images.removeAt(i)),isLoading:st.isLoading,onSubmit:submit));}}
